func buildPrompt(workDir string, b *bead.Bead, refs []executeBeadGoverningRef, artifacts *executeBeadArtifacts, baseRev, promptOverride, harness string, contextBudget string) ([]byte, string, error) {
	if strings.TrimSpace(promptOverride) != "" {
		path := promptOverride
		if !filepath.IsAbs(path) {
			path = filepath.Join(workDir, path)
		}
		data, err := readPromptFileBounded(path)
		if err != nil {
			return nil, "", fmt.Errorf("reading prompt override %q: %w", promptOverride, err)
		}
		return data, promptOverride, nil
	}

	var sb strings.Builder
	sb.WriteString("<execute-bead>\n")

	fmt.Fprintf(&sb, "  <bead id=\"%s\">\n", xmlAttrEscape(b.ID))
	fmt.Fprintf(&sb, "    <title>%s</title>\n", xmlEscape(strings.TrimSpace(b.Title)))

	desc := strings.TrimSpace(b.Description)
	if desc == "" {
		sb.WriteString("    <description/>\n")
	} else {
		fmt.Fprintf(&sb, "    <description>\n%s\n    </description>\n", xmlEscape(desc))
	}

	acc := strings.TrimSpace(b.Acceptance)
	if acc == "" {
		sb.WriteString("    <acceptance/>\n")
	} else {
		fmt.Fprintf(&sb, "    <acceptance>\n%s\n    </acceptance>\n", xmlEscape(acc))
	}

	// Bead notes carry review findings from prior iterations, escalation
	// context, or operator hints that did not fit into the description at
	// creation time. Threading them into the prompt as a distinct section
	// lets the agent act on them without the operator having to rewrite the
	// description in place on every reopen.
	if notes := strings.TrimSpace(b.Notes); notes != "" {
		fmt.Fprintf(&sb, "    <notes>\n%s\n    </notes>\n", xmlEscape(notes))
	}

	if len(b.Labels) > 0 {
		fmt.Fprintf(&sb, "    <labels>%s</labels>\n", xmlEscape(strings.Join(b.Labels, ", ")))
	} else {
		sb.WriteString("    <labels/>\n")
	}

	metaAttrs := make([]string, 0, 6)
	if b.Parent != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("parent=\"%s\"", xmlAttrEscape(b.Parent)))
	}
	if specID, _ := b.Extra["spec-id"].(string); strings.TrimSpace(specID) != "" {
		metaAttrs = append(metaAttrs, fmt.Sprintf("spec-id=\"%s\"", xmlAttrEscape(strings.TrimSpace(specID))))
	}
	metaAttrs = append(metaAttrs, fmt.Sprintf("base-rev=\"%s\"", xmlAttrEscape(baseRev)))
	metaAttrs = append(metaAttrs, fmt.Sprintf("bundle=\"%s\"", xmlAttrEscape(artifacts.DirRel)))
	fmt.Fprintf(&sb, "    <metadata %s/>\n", strings.Join(metaAttrs, " "))
	sb.WriteString("  </bead>\n")

	// For minimal budget, omit full governing refs and only include bead metadata.
	// This significantly reduces prompt size for cheap-tier attempts on local models.
	if contextBudget == "minimal" {
		sb.WriteString("  <governing>\n    <note>No governing references.</note>\n  </governing>\n")
	} else {
		if len(refs) == 0 {
			fmt.Fprintf(&sb, "  <governing>\n    <note>%s</note>\n  </governing>\n", xmlEscape(executeBeadMissingGoverningText))
		} else {
			sb.WriteString("  <governing>\n")
			for _, ref := range refs {
				attrs := fmt.Sprintf("id=\"%s\" path=\"%s\"", xmlAttrEscape(ref.ID), xmlAttrEscape(ref.Path))
				if strings.TrimSpace(ref.Title) == "" {
					fmt.Fprintf(&sb, "    <ref %s/>\n", attrs)
				} else {
					fmt.Fprintf(&sb, "    <ref %s>%s</ref>\n", attrs, xmlEscape(strings.TrimSpace(ref.Title)))
				}
			}
			sb.WriteString("  </governing>\n")
		}
	}

	instructions := strings.ReplaceAll(executeBeadInstructionsText(harness), "{{.AttemptDir}}", artifacts.DirRel)
	fmt.Fprintf(&sb, "  <instructions>\n%s\n  </instructions>\n", xmlEscape(instructions))

	sb.WriteString("</execute-bead>\n")

	return []byte(sb.String()), "synthesized", nil
}

// promptSHA returns the hex-encoded sha256 of the rendered prompt bytes.
// Used as manifest.prompt_sha so analytics can group attempts by the exact
// prompt that produced them.
func promptSHA(promptContent []byte) string {
	sum := sha256.Sum256(promptContent)
	return hex.EncodeToString(sum[:])
}

func beadMetadata(b *bead.Bead) map[string]any {
	if len(b.Extra) == 0 {
		return nil
	}
	meta := make(map[string]any, len(b.Extra))
	for k, v := range b.Extra {
		meta[k] = v
	}
	return meta
}

// executeBeadUsage is the machine-readable schema for usage.json.
// It is written when the harness reports token usage or cost.
type executeBeadUsage struct {
	AttemptID    string  `json:"attempt_id"`
	Harness      string  `json:"harness,omitempty"`
	Provider     string  `json:"provider,omitempty"`
	Model        string  `json:"model,omitempty"`
	Tokens       int     `json:"tokens"`
	InputTokens  int     `json:"input_tokens,omitempty"`
	OutputTokens int     `json:"output_tokens,omitempty"`
	CostUSD      float64 `json:"cost_usd,omitempty"`
}

// VerifyCleanWorktree checks that the project root's working tree has no
// untracked execution evidence files for the given attempt. If evidence files
// remain (e.g. because the land flow did not commit them), it stages and
// commits them as a safety net. Returns nil when the evidence dir is clean
// or was successfully committed.
func VerifyCleanWorktree(projectRoot, attemptID string) error {
	if attemptID == "" {
		return nil
	}
	evidenceDir := filepath.ToSlash(filepath.Join(ExecuteBeadArtifactDir, attemptID))

	out, _ := internalgit.Command(context.Background(), projectRoot, "status", "--porcelain", "--", evidenceDir).Output()
	if len(strings.TrimSpace(string(out))) == 0 {
		return nil
	}

	// Exclude embedded session logs from the evidence commit; they stay
	// on disk for post-hoc inspection but must NOT be tracked — the
	// multi-thousand-line .jsonl files are what caused ddx-39e27896
	// (retry prompts ballooning past provider context limits).
	// manifest.json, result.json, prompt.md, usage.json remain tracked
	// per the existing audit-trail contract (gitignore un-ignores them).
	addArgs := append([]string{"add", "--", evidenceDir}, EvidenceLandExcludePathspecs()...)
	addOut, addErr := internalgit.Command(context.Background(), projectRoot, addArgs...).CombinedOutput()
	if addErr != nil {
		return fmt.Errorf("staging leftover evidence: %s: %w", strings.TrimSpace(string(addOut)), addErr)
	}
	diffOut, _ := internalgit.Command(context.Background(), projectRoot, "diff", "--cached", "--name-only", "--", evidenceDir).Output()
	if len(strings.TrimSpace(string(diffOut))) == 0 {
		return nil
	}
	msg := fmt.Sprintf("chore: add execution evidence [%s]", shortAttempt(attemptID))
	commitOut, commitErr := internalgit.Command(context.Background(), projectRoot,
		"-c", "user.name=ddx-land-coordinator",
		"-c", "user.email=coordinator@ddx.local",
		"commit", "-m", msg,
	).CombinedOutput()
	if commitErr != nil {

package agent

import (
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// representativePromptBead returns the deterministic bead used by the
// prompt-size fixture and the prompt_sha test. Holding it constant means
// rendered prompt sha and word/byte counts only change when the static
// instructions change — which is exactly what we want to surface.
func representativePromptBead() *bead.Bead {
	return &bead.Bead{
		ID:    "ddx-promptsize-fixture",
		Title: "Representative bead for prompt-size measurement",
		Description: "Static fixture used by Story 12 prompt-size report and " +
			"prompt_sha analytics. Description body is deliberately ordinary " +
			"prose so word/byte counts reflect the static instructions, not " +
			"the bead body.",
		Acceptance: "AC1: prompt renders deterministically.\n" +
			"AC2: word and byte counts are reported per (variant, contextBudget).",
		Labels: []string{"phase:2", "story:12", "tier:cheap"},
		Extra:  map[string]any{"spec-id": "FEAT-022"},
	}
}

// renderPromptForSize renders a prompt for the given harness selector and
// contextBudget using a fixed in-memory artifact bundle. It does not touch
// the filesystem so the fixture is hermetic.
func renderPromptForSize(t *testing.T, harness, contextBudget string) []byte {
	t.Helper()
	const attemptID = "20260101T000000-promptsize"
	arts := &executeBeadArtifacts{
		DirRel:      ".ddx/executions/" + attemptID,
		PromptRel:   ".ddx/executions/" + attemptID + "/prompt.md",
		ManifestRel: ".ddx/executions/" + attemptID + "/manifest.json",
		ResultRel:   ".ddx/executions/" + attemptID + "/result.json",
		ChecksRel:   ".ddx/executions/" + attemptID + "/checks.json",
		UsageRel:    ".ddx/executions/" + attemptID + "/usage.json",
	}
	b := representativePromptBead()
	// Empty refs to keep the fixture hermetic — buildPrompt will emit the
	// missing-governing fallback note for the non-minimal budget, which
	// matches the AC for that case.
	content, _, err := buildPrompt(t.TempDir(), b, nil, arts, "deadbeefdeadbeef", "", harness, contextBudget)
	if err != nil {
		t.Fatalf("buildPrompt(%s, %q): %v", harness, contextBudget, err)
	}
	return content
}

// TestPromptSizeReport renders the execute-bead prompt for both variants
// (Claude harness, Agent harness) at each contextBudget label ("" full,
// "minimal") and writes a deterministic word/byte report. CI uploads the
// report path named by DDX_PROMPT_SIZE_REPORT as an artifact so accidental
// prompt bloat shows up as a diff in the artifact across runs.
func TestPromptSizeReport(t *testing.T) {
	type row struct {
		Variant       string `json:"variant"`
		Harness       string `json:"harness"`
		ContextBudget string `json:"context_budget"`
		Words         int    `json:"words"`
		Bytes         int    `json:"bytes"`
		PromptSHA     string `json:"prompt_sha"`
	}

	// Selector at execute_bead.go routes (agent|fiz|embedded) to the Agent
	// variant; everything else (claude/codex/opencode/unknown) to the Claude
	// variant. One representative harness per variant is enough.
	cases := []struct{ variant, harness string }{
		{"claude", "claude"},
		{"agent", "agent"},
	}
	budgets := []string{"", "minimal"}

	rows := make([]row, 0, len(cases)*len(budgets))
	for _, c := range cases {
		for _, budget := range budgets {
			content := renderPromptForSize(t, c.harness, budget)
			sum := sha256.Sum256(content)
			rows = append(rows, row{
				Variant:       c.variant,
				Harness:       c.harness,
				ContextBudget: budget,
				Words:         len(strings.Fields(string(content))),
				Bytes:         len(content),
				PromptSHA:     hex.EncodeToString(sum[:]),
			})
		}
	}

	sort.Slice(rows, func(i, j int) bool {
		if rows[i].Variant != rows[j].Variant {
			return rows[i].Variant < rows[j].Variant
		}
		return rows[i].ContextBudget < rows[j].ContextBudget
	})

	var report strings.Builder
	report.WriteString("# execute-bead prompt size report\n")
	report.WriteString("# variant\tharness\tcontext_budget\twords\tbytes\tprompt_sha\n")
	for _, r := range rows {
		budget := r.ContextBudget
		if budget == "" {
			budget = "full"
		}
		fmt.Fprintf(&report, "%s\t%s\t%s\t%d\t%d\t%s\n",
			r.Variant, r.Harness, budget, r.Words, r.Bytes, r.PromptSHA)
	}

	// Always log the report to test output — that alone makes CI surface
	// it via the existing test-log capture even if the artifact step is
	// not configured.
	t.Logf("\n%s", report.String())

	// Sanity: every row produced non-empty output.
	for _, r := range rows {
		if r.Words == 0 || r.Bytes == 0 {
			t.Errorf("empty rendered prompt for variant=%s budget=%q", r.Variant, r.ContextBudget)
		}
	}
	// Minimal must be strictly smaller than full for both variants — the
	// fixture's reason for existing is to catch regressions on the cheap-tier
	// path.
	byKey := map[string]row{}
	for _, r := range rows {
		byKey[r.Variant+"|"+r.ContextBudget] = r
	}
	for _, v := range []string{"claude", "agent"} {
		full := byKey[v+"|"]
		min := byKey[v+"|minimal"]
		if min.Bytes >= full.Bytes {
			t.Errorf("variant %s: minimal bytes %d not smaller than full bytes %d",
				v, min.Bytes, full.Bytes)
		}
	}

	// Write the human-readable report alongside a JSON sibling for
	// machine consumers. CI sets DDX_PROMPT_SIZE_REPORT to a path under the
	// workspace and uploads it as an artifact; locally the test falls back
	// to t.TempDir() so it never pollutes the working tree.
	outPath := strings.TrimSpace(os.Getenv("DDX_PROMPT_SIZE_REPORT"))
	if outPath == "" {
		outPath = filepath.Join(t.TempDir(), "prompt-size-report.txt")
	}
	if err := os.MkdirAll(filepath.Dir(outPath), 0o755); err != nil {
		t.Fatalf("mkdir report dir: %v", err)
	}
	if err := os.WriteFile(outPath, []byte(report.String()), 0o644); err != nil {
		t.Fatalf("writing prompt-size report: %v", err)
	}
	jsonPath := strings.TrimSuffix(outPath, filepath.Ext(outPath)) + ".json"
	jb, err := json.MarshalIndent(rows, "", "  ")
	if err != nil {
		t.Fatalf("marshal rows: %v", err)
	}
	if err := os.WriteFile(jsonPath, append(jb, '\n'), 0o644); err != nil {
		t.Fatalf("writing prompt-size report json: %v", err)
	}
	t.Logf("prompt-size report written to %s (and %s)", outPath, jsonPath)
}

// TestPromptSHA_DeterministicAcrossRenders asserts that the helper
// promptSHA used to populate manifest.prompt_sha is stable across renders
// of the same inputs. Without this, analytics grouping by prompt_sha would
// fragment across attempts that share a prompt.
func TestPromptSHA_DeterministicAcrossRenders(t *testing.T) {
	a := renderPromptForSize(t, "claude", "")
	b := renderPromptForSize(t, "claude", "")
	if promptSHA(a) != promptSHA(b) {
		t.Fatalf("promptSHA not deterministic: %s vs %s", promptSHA(a), promptSHA(b))
	}
	c := renderPromptForSize(t, "agent", "")
	if promptSHA(a) == promptSHA(c) {
		t.Fatalf("promptSHA collided across variants — selector is not influencing the prompt body")
	}
}

package agent

import (
	"strings"
	"testing"
)

// renderInstructionsForGuardrails returns the post-{{.AttemptDir}}-substitution
// instructions string for the given harness selector. Guardrail tests assert
// on this pre-XML-escape form so substring checks against `<bead-id>`,
// `<specific-paths>`, etc. are not distorted by XML entity encoding (the
// rendered prompt encloses instructions in <instructions>...</instructions>
// and so escapes angle brackets and apostrophes). The bead body itself is
// excluded — invariants must come from the static prompt, not the bead.
func renderInstructionsForGuardrails(t *testing.T, harness, contextBudget string) string {
	t.Helper()
	const attemptDir = ".ddx/executions/20260101T000000-guardrails"
	raw := executeBeadInstructionsText(harness)
	return strings.ReplaceAll(raw, "{{.AttemptDir}}", attemptDir)
}

// renderFullPromptForGuardrails returns the byte-for-byte rendered prompt
// (XML-wrapped, attempt-dir-substituted) for the given harness and
// contextBudget. Used by tests that need to verify buildPrompt-level
// behaviour (governing fallback, minimal-budget gating).
func renderFullPromptForGuardrails(t *testing.T, harness, contextBudget string) string {
	t.Helper()
	const attemptID = "20260101T000000-guardrails"
	arts := &executeBeadArtifacts{
		DirRel:      ".ddx/executions/" + attemptID,
		PromptRel:   ".ddx/executions/" + attemptID + "/prompt.md",
		ManifestRel: ".ddx/executions/" + attemptID + "/manifest.json",
		ResultRel:   ".ddx/executions/" + attemptID + "/result.json",
		ChecksRel:   ".ddx/executions/" + attemptID + "/checks.json",
		UsageRel:    ".ddx/executions/" + attemptID + "/usage.json",
	}
	b := representativePromptBead()
	content, _, err := buildPrompt(t.TempDir(), b, nil, arts, "deadbeefdeadbeef", "", harness, contextBudget)
	if err != nil {
		t.Fatalf("buildPrompt(%s, %q): %v", harness, contextBudget, err)
	}
	return string(content)
}

// TestExecuteBeadInstructionsLoadBearingGuardrails enforces FEAT-022's
// static-prompt minimum-prompt rule: every guardrail listed in the
// file-level comment block above the constants in execute_bead.go MUST
// appear in the rendered prompt for each (harness, variant). This is the
// regression test for the comment-list contract — adding a new guardrail
// requires adding it to BOTH the comment block AND this list.
func TestExecuteBeadInstructionsLoadBearingGuardrails(t *testing.T) {
	// Each entry: a substring (or substring family) that proves the
	// corresponding guardrail survived the rewrite. Substrings are picked
	// to be robust to wording shuffles within the same guardrail.
	type guardrail struct {
		name     string
		any      []string // pass if ANY of these substrings is present
		variants []string // empty = both; "claude" or "agent" = that variant only
	}
	guardrails := []guardrail{
		{name: "ac_anti_handwave", any: []string{
			"every AC must be provably satisfied",
			"Every AC must be satisfied by code",
		}},
		{name: "read_first", any: []string{"Read first"}},
		{name: "commit_subject_bead_id", any: []string{"[<bead-id>]"}},
		{name: "commit_exactly_once", any: []string{"Commit exactly once", "commit exactly once"}},
		{name: "git_add_specific_paths", any: []string{"git add <specific-paths>"}},
		{name: "no_git_add_dash_a", any: []string{"never `git add -A`", "never git add -A"}},
		{name: "no_red_code", any: []string{"Do not commit red code"}},
		{name: "no_modify_outside_scope", any: []string{"outside the bead's scope", "outside the bead's named scope"}},
		{name: "never_ddx_init", any: []string{"Never run `ddx init`", "never `ddx init`"}},
		{name: "executions_intact", any: []string{".ddx/executions/"}},
		{name: "no_rewrite_claude_md", any: []string{"CLAUDE.md, AGENTS.md"}},
		{name: "bead_overrides_defaults", any: []string{"override CLAUDE.md", "overrides project defaults"}},
		{name: "reports_attempt_dir", any: []string{".ddx/executions/20260101T000000-guardrails/"}},
		{name: "reports_no_tmp", any: []string{"/tmp"}},
		{name: "no_changes_rationale", any: []string{"no_changes_rationale.txt"}},
		{name: "step0_size_check", any: []string{"## Step 0: size check"}},
		{name: "decompose_bead_create", any: []string{"ddx bead create"}},
		{name: "decompose_bead_dep_add", any: []string{"ddx bead dep add"}},
		{name: "decompose_bead_update", any: []string{"ddx bead update"}},
		{name: "review_is_a_gate", any: []string{"review is a gate", "review is a gate, not an escape hatch"}},
		{name: "blocking_review_findings", any: []string{"BLOCKING `<review-findings>`", "BLOCKING <review-findings>"}},
		{name: "no_no_changes_with_blocking", any: []string{"do not declare `no_changes` with blocking findings open"}},
		{name: "stop_after_commit", variants: []string{"agent"}, any: []string{"Stop immediately after the commit"}},
		{name: "agent_use_tools_not_bash", variants: []string{"agent"}, any: []string{"`bash: cat`", "`bash: rg`"}},
	}

	cases := []struct{ variant, harness string }{
		{"claude", "claude"},
		{"agent", "agent"},
	}
	for _, c := range cases {
		c := c
		t.Run(c.variant, func(t *testing.T) {
			rendered := renderInstructionsForGuardrails(t, c.harness, "")
			for _, g := range guardrails {
				if len(g.variants) > 0 && !contains(g.variants, c.variant) {
					continue
				}
				if !anyContains(rendered, g.any) {
					t.Errorf("guardrail %q missing from %s variant; expected one of %v",
						g.name, c.variant, g.any)
				}
			}
		})
	}
}

// TestExecuteBeadInstructionsHarnessSelector covers the routing at
// executeBeadInstructionsText: agent/fiz/embedded route to the Agent
// variant; claude/codex/opencode/unknown/empty route to the Claude
// variant. AC10 forbids any new per-harness branches beyond Claude/Agent.
func TestExecuteBeadInstructionsHarnessSelector(t *testing.T) {
	cases := []struct {
		harness string
		want    string // "agent" or "claude"
	}{
		{"agent", "agent"},
		{"fiz", "agent"},
		{"embedded", "agent"},
		{"AGENT", "agent"},
		{"  Fiz  ", "agent"},

		{"claude", "claude"},
		{"codex", "claude"},
		{"opencode", "claude"},
		{"unknown", "claude"},
		{"", "claude"},
		{"GPT-4", "claude"},
	}
	for _, c := range cases {
		c := c
		t.Run(c.harness+"_to_"+c.want, func(t *testing.T) {
			got := executeBeadInstructionsText(c.harness)
			switch c.want {
			case "agent":
				if got != executeBeadInstructionsAgentText {
					t.Errorf("harness %q: expected Agent variant, got Claude", c.harness)
				}
			case "claude":
				if got != executeBeadInstructionsClaudeText {
					t.Errorf("harness %q: expected Claude variant, got Agent", c.harness)
				}
			}
		})
	}
}

// TestExecuteBeadInstructionsRenderedInvariants is the AC4 substring-invariant
// test: rendered prompts MUST contain the named substrings in every (variant,
// non-minimal contextBudget) pair. These are the operational primitives the
// agent has to know about; if a tightening pass drops one, the bead loop
// silently degrades.
func TestExecuteBeadInstructionsRenderedInvariants(t *testing.T) {
	cases := []struct{ variant, harness string }{
		{"claude", "claude"},
		{"agent", "agent"},
	}
	required := []string{
		"[<bead-id>]",
		"git add <specific-paths>",
		"git add -A", // appears as part of "never `git add -A`"
		"no_changes_rationale.txt",
		".ddx/executions/",
		"ddx bead create",
		"ddx bead dep add",
		"ddx bead update",
	}
	for _, c := range cases {
		c := c
		t.Run(c.variant, func(t *testing.T) {
			rendered := renderInstructionsForGuardrails(t, c.harness, "")
			for _, sub := range required {
				if !strings.Contains(rendered, sub) {
					t.Errorf("rendered %s prompt missing required substring %q", c.variant, sub)
				}
			}
		})
	}
}

// TestExecuteBeadInstructionsMissingGoverningGate covers AC5: non-minimal
// renders include executeBeadMissingGoverningText when refs are empty;
// contextBudget=="minimal" omits governing refs entirely (replaced by the
// cheap-tier "No governing references." note).
func TestExecuteBeadInstructionsMissingGoverningGate(t *testing.T) {
	full := renderFullPromptForGuardrails(t, "claude", "")
	if !strings.Contains(full, executeBeadMissingGoverningText) {
		t.Fatalf("full-budget render with empty refs must include executeBeadMissingGoverningText")
	}
	minimal := renderFullPromptForGuardrails(t, "claude", "minimal")
	if strings.Contains(minimal, executeBeadMissingGoverningText) {
		t.Errorf("minimal-budget render must NOT include executeBeadMissingGoverningText")
	}
	if !strings.Contains(minimal, "No governing references") {
		t.Errorf("minimal-budget render must contain its short fallback note")
	}
	fullA := renderFullPromptForGuardrails(t, "agent", "")
	if !strings.Contains(fullA, executeBeadMissingGoverningText) {
		t.Fatalf("agent variant full-budget render with empty refs must include executeBeadMissingGoverningText")
	}
}

// TestExecuteBeadInstructionsSizeFloor is AC2: the rendered prompt for the
// representative bead is at least 30% shorter (word count) than the pre-B2
// baseline for both variants. Hard-coded baselines come from the size
// report at HEAD before this bead landed.
func TestExecuteBeadInstructionsSizeFloor(t *testing.T) {
	// Pre-B2 baselines from TestPromptSizeReport on the parent commit
	// (63bb619 — tracked by metadata.base-rev on this bead).
	const (
		baselineClaude = 1048
		baselineAgent  = 968
		floor          = 0.70 // ≥30% shorter ⇒ words ≤ 0.70 * baseline
	)
	cases := []struct {
		variant, harness string
		baseline         int
	}{
		{"claude", "claude", baselineClaude},
		{"agent", "agent", baselineAgent},
	}
	for _, c := range cases {
		c := c
		t.Run(c.variant, func(t *testing.T) {
			rendered := renderFullPromptForGuardrails(t, c.harness, "")
			words := len(strings.Fields(rendered))
			limit := int(float64(c.baseline) * floor)
			if words > limit {
				t.Errorf("AC2 size floor: %s variant rendered %d words; must be ≤ %d (%.0f%% of baseline %d)",
					c.variant, words, limit, floor*100, c.baseline)
			}
			t.Logf("%s variant rendered %d words (baseline %d, limit %d)",
				c.variant, words, c.baseline, limit)
		})
	}
}

